#include <stdio.h>

unsigned char set_bit(unsigned char val, int pos) {
    return val | (1 << pos);
}

unsigned char clear_bit(unsigned char val, int pos) {
    return val & ~(1 << pos);
}

unsigned char toggle_bit(unsigned char val, int pos) {
    return val ^ (1 << pos);
}

int test_bit(unsigned char val, int pos) {
    return (val >> pos) & 1;
}

int main(void) {
    {
        printf("%d\n", (int)(set_bit(0xA5, 3)));
        printf("%d\n", (int)(set_bit(0xA5, 5)));
        printf("%d\n", (int)(set_bit(0xFE, 0)));
        printf("%d\n", (int)(set_bit(0xFF, 7)));
    }
    {
        printf("%d\n", (int)(clear_bit(0xA5, 2)));
        printf("%d\n", (int)(clear_bit(0xA5, 5)));
        printf("%d\n", (int)(clear_bit(0xFE, 7)));
        printf("%d\n", (int)(clear_bit(0xFF, 0)));
    }
    {
        printf("%d\n", (int)(toggle_bit(0xA5, 0)));
        printf("%d\n", (int)(toggle_bit(0xA4, 0)));
        printf("%d\n", (int)(toggle_bit(0xA5, 5)));
        printf("%d\n", (int)(toggle_bit(0xA5, 7)));
    }
    {
        printf("%d\n", (int)(test_bit(0xA5, 0)));
        printf("%d\n", (int)(test_bit(0xA5, 1)));
        printf("%d\n", (int)(test_bit(0xA5, 5)));
        printf("%d\n", (int)(test_bit(0xA5, 7)));
    }
    return 0;
}

